If you use something like that: http://kinto.readthedocs.io/en/stable/configuration/production.html#running-with-uwsgi

For instance it looks like that:

```
[uwsgi]
wsgi-file = app.wsgi
enable-threads = true
socket = /home/ubuntu/.run/uwsgi/kinto.sock
chmod-socket = 666
processes =  3
master = true
module = kinto
harakiri = 120
uid = ubuntu
gid = ubuntu
virtualenv = /home/ubuntu/venvs/kinto
lazy = true
lazy-apps = true
single-interpreter = true
buffer-size = 65535
post-buffering = 65535
```

Then you can run uwsgi and have nginx serve the service in HTTPS with a config like that:

```
server {
    listen 443 ssl;

    server_name kinto.yourdomain.com;

    ssl_certificate /etc/nginx/ssl/certificate.crt;
    ssl_certificate_key /etc/nginx/ssl/certificate.key;

    location /attachments {
        root /home/ubuntu;
    }

    location /v1 {
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
        proxy_set_header X-Forwarded-Proto $scheme;
        proxy_set_header Host $http_host;
        proxy_redirect off;
        proxy_intercept_errors on;
        uwsgi_pass unix:///home/ubuntu/.run/uwsgi/kinto.sock;
        uwsgi_read_timeout 120;
        uwsgi_send_timeout 120;
        include uwsgi_params;
    }

    location / {
        return 301 https://$host/v1$request_uri;
    }
}
```

If you need an intermediate certificate chain, you can use this solution: https://scottlinux.com/2013/09/02/how-to-configure-ssl-certificate-chain-for-nginx/

